namespace sv_19de85d275854819b7631373fb8b9e55.Services;

/// <summary>
/// Scoped service holding the current warehouse selection for a single user circuit.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
        ("WH-D", "Warehouse D"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>Raised when the selected warehouse changes.</summary>
    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_19de85d275854819b7631373fb8b9e55.Services;

/// <summary>
/// Simulates a database query for low-stock item counts.
/// Registered as scoped so each circuit gets its own Random instance.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async database call
        return Task.FromResult(_random.Next(0, 16));
    }
}

@using sv_19de85d275854819b7631373fb8b9e55.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="me-2 mb-0 text-nowrap fw-semibold">Warehouse:</label>
    <select class="form-select form-select-sm" style="width:auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
            await WarehouseState.SetWarehouseAsync(id);
    }

    // Re-render if another component on the same circuit changes the warehouse
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateChanged;
    }

    private async Task StateChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateChanged;
    }
}

@using sv_19de85d275854819b7631373fb8b9e55.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="alert-badge-wrapper">
    @if (_lowStockCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-2">@_lowStockCount</span>
    }
    else if (_loaded)
    {
        <span class="badge bg-success rounded-pill ms-2">0</span>
    }
</span>

@code {
    private int _lowStockCount;
    private bool _loaded;

    /// <summary>
    /// When true, this badge instance owns a polling timer.
    /// The sidebar badge does NOT poll — it refreshes reactively when the dashboard pushes new data.
    /// </summary>
    [Parameter] public bool Poll { get; set; }

    /// <summary>Interval in seconds between polls (default 10).</summary>
    [Parameter] public int IntervalSeconds { get; set; } = 10;

    /// <summary>
    /// Optional callback invoked after every successful refresh.
    /// The Dashboard uses this to notify the sidebar badge via shared state.
    /// </summary>
    [Parameter] public EventCallback<int> OnCountUpdated { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAsync();

        if (Poll)
            StartPolling();
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(IntervalSeconds));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _loaded = true;
        await InvokeAsync(StateHasChanged);

        if (OnCountUpdated.HasDelegate)
            await OnCountUpdated.InvokeAsync(_lowStockCount);
    }

    private async Task OnWarehouseChanged()
    {
        // Warehouse changed — refresh immediately and restart polling cycle
        if (Poll)
            StartPolling();

        await RefreshAsync();
    }

    /// <summary>
    /// Public method so external components can push an updated count
    /// without a redundant service call.
    /// </summary>
    public async Task SetCount(int count)
    {
        _lowStockCount = count;
        _loaded = true;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

@page "/dashboard"
@rendermode InteractiveServer

@using sv_19de85d275854819b7631373fb8b9e55.Services
@using sv_19de85d275854819b7631373fb8b9e55.Components.Shared
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

