        <h5 class="card-title">📋 Recent Activity</h5>
        <p class="text-muted">Activity feed for @WarehouseState.CurrentWarehouseName would appear here.</p>
    </div>
</div>

@code {
    private AlertBadge? _dashboardBadge;
    private int _lastAlertCount;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    private async Task OnWarehouseChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertCountUpdated(int count)
    {
        _lastAlertCount = count;
        // Push the latest count to the sidebar badge via shared state event
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
    }
}

