@page "/dashboard"
@rendermode InteractiveServer

@using sv_19de85d275854819b7631373fb8b9e55.Services
@using sv_19de85d275854819b7631373fb8b9e55.Components.Shared
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            📦 @WarehouseState.CurrentWarehouseName
        </h5>
        <p class="card-text">
            Currently managing <strong>@WarehouseState.CurrentWarehouseName</strong>
            (<code>@WarehouseState.CurrentWarehouseId</code>).
            Use the warehouse selector in the header to switch sites.
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body d-flex align-items-center">
        <h5 class="card-title mb-0 me-3">⚠️ Low-Stock Alerts</h5>
        <AlertBadge @ref="_dashboardBadge" Poll="true" IntervalSeconds="10"
                    OnCountUpdated="OnAlertCountUpdated" />
    </div>
    <div class="card-footer text-muted">
        Checked every 10 seconds. Count refreshes automatically when you switch warehouses.
    </div>
</div>

<div class="card">
    <div class="card-body">
        <h5 class="card-title">📋 Recent Activity</h5>
        <p class="text-muted">Activity feed for @WarehouseState.CurrentWarehouseName would appear here.</p>
    </div>
</div>

@code {
    private AlertBadge? _dashboardBadge;
    private int _lastAlertCount;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    private async Task OnWarehouseChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertCountUpdated(int count)
    {
        _lastAlertCount = count;
        // Push the latest count to the sidebar badge via shared state event
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
    }
}

